#include <stdio.h>
#include <stdlib.h>

// Function to remove duplicates based on threshold
int* remove_duplicates(int* numbers, int size, int threshold, int* result_size) {
    // Step 1: Count the frequency of each number
    int max_num = 0;
    for (int i = 0; i < size; i++) {
        if (numbers[i] > max_num) {
            max_num = numbers[i];
        }
    }

    // Allocate memory for frequency array
    int* frequency = (int*)malloc((max_num + 1) * sizeof(int));
    if (!frequency) {
        fprintf(stderr, "Memory allocation failed.\n");
        return NULL;
    }

    for (int i = 0; i <= max_num; i++) {
        frequency[i] = 0;
    }

    for (int i = 0; i < size; i++) {
        frequency[numbers[i]]++;
    }

    // Step 2: Build the result list
    int* result = (int*)malloc(size * sizeof(int));
    if (!result) {
        fprintf(stderr, "Memory allocation failed.\n");
        free(frequency);
        return NULL;
    }

    int index = 0;

    for (int i = 0; i < size; i++) {
        if (frequency[numbers[i]] <= threshold) {
            result[index++] = numbers[i];
            frequency[numbers[i]] = threshold + 1; // Mark as processed
        }
    }

    // Update result_size and return
    *result_size = index;
    return result;
}

